import { Injectable } from '@nestjs/common';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { Counter, Histogram } from 'prom-client';

/**
 * Custom business metrics (README §2.6 Monitoring). Exposed at `/metrics` via
 * @willsoto/nestjs-prometheus alongside the default process metrics.
 */
@Injectable()
export class BusinessMetricsService {
  constructor(
    @InjectMetric('smartcart_checkout_completions_total')
    private readonly checkoutCounter: Counter<string>,
    @InjectMetric('smartcart_points_awarded')
    private readonly pointsHistogram: Histogram<string>,
    @InjectMetric('smartcart_qr_generations_total')
    private readonly qrCounter: Counter<string>,
  ) {}

  /** A checkout completed and credited `points` (README W1 step 5). */
  recordCheckout(points: number): void {
    this.checkoutCounter.inc();
    this.pointsHistogram.observe(points);
  }

  /** A checkout QR was generated. */
  recordQrGenerated(): void {
    this.qrCounter.inc();
  }
}
